<span class="line"><span style="color:#F8F8F2;">Python </span><span style="color:#AE81FF;">3.10</span><span style="color:#F8F8F2;">.10 (main, Feb  </span><span style="color:#AE81FF;">8</span><span style="color:#AE81FF;"> 2023</span><span style="color:#F8F8F2;">, </span><span style="color:#AE81FF;">0</span><span style="color:#F44747;">5</span><span style="color:#F8F8F2;">:</span><span style="color:#AE81FF;">34</span><span style="color:#F8F8F2;">:</span><span style="color:#AE81FF;">50</span><span style="color:#F8F8F2;">) [Clang </span><span style="color:#AE81FF;">14.0</span><span style="color:#F8F8F2;">.0 (clang</span><span style="color:#F92672;">-</span><span style="color:#AE81FF;">1400.0</span><span style="color:#F8F8F2;">.29.202)] on darwin</span></span>
