<span class="line"><span style="color:#F92672;">&gt;&gt;&gt;</span><span style="color:#F8F8F2;"> c </span><span style="color:#F92672;">=</span><span style="color:#F8F8F2;"> Category(</span><span style="color:#FD971F;font-style:italic;">name</span><span style="color:#F92672;">=</span><span style="color:#E6DB74;">&#39;category test&#39;</span><span style="color:#F8F8F2;">)</span></span>
